var validateAdditionalComments = "YES";
if (this.PE_SAVE_SUBMIT_TX2 == "SAVE" || this.PE_TAX_REVIEW_NOT_APPLICABLE !== true) {
    validateAdditionalComments = "NO";
}
return validateAdditionalComments;

/*****************************
 * Validate Documents Grid
 * 
 * by Cinthia Romero
 * modified by Adriana Centellas
 ****************************/

/**
 * Validate Document
 *
 * by Cinthia Romero
 */
function validateDocument(value) {
    return (value !== null && value !== "" && value !== 0 && value !== [] && (typeof value !== "undefined"));
}

//Initialize Variables
var validateDocuments = {};
validateDocuments["VALIDATE"] = "NO";
validateDocuments["MESSAGE"] = "";
if (this.PE_TAX_REVIEW_NOT_APPLICABLE !== true && this.PE_SAVE_SUBMIT_TX2 != "SAVE") {
	if (Array.isArray(this.PE_TAX_REVIEW_MEMO_DOCUMENTS) && this.PE_TAX_REVIEW_MEMO_DOCUMENTS.length <= 0) {
		validateDocuments["VALIDATE"] = "YES";
        validateDocuments["MESSAGE"] = "At least one document is required";
	} else {
		let allDocumentsExist = "YES";
		//let allDocumentDescriptionsOk = "YES";
		this.PE_TAX_REVIEW_MEMO_DOCUMENTS.forEach(row => {
			if (!validateDocument(row.PE_TAX_REVIEW_MEMO_UPLOAD)) {
				allDocumentsExist = "NO";
			}
			/*
			if (row.PE_TAX_REVIEW_MEMO_DESCRIPTION == "") {
				allDocumentDescriptionsOk = "NO";
			}*/
		});
		if (allDocumentsExist == "NO"/* || allDocumentDescriptionsOk == "NO"*/) {
		    validateDocuments["VALIDATE"] = "YES";
            validateDocuments["MESSAGE"] = "Please upload a valid document";
		}
	}
}
return validateDocuments;

